export abstract class BaseRepository<T extends { id: string }> {
  constructor(protected collection: Collection<T>) {}

  async findById(id: string): Promise<T | null> {
    return this.collection.findOne({ id } as any);
  }

  async findMany(filter: Partial<T>, options?: { limit?: number; offset?: number; sort?: Record<string, 1 | -1> }): Promise<T[]> {
    let query = this.collection.find(filter as any);
    if (options?.sort) query = query.sort(options.sort);
    if (options?.offset) query = query.skip(options.offset);
    if (options?.limit) query = query.limit(options.limit);
    return query.toArray();
  }

  async count(filter?: Partial<T>): Promise<number> {
    return this.collection.countDocuments(filter as any ?? {});
  }

  abstract validate(entity: Omit<T, 'id'>): Promise<void>;

  async create(data: Omit<T, 'id'>): Promise<T> {
    await this.validate(data);
    const entity = { ...data, id: generateId() } as T;
    await this.collection.insertOne(entity as any);
    return entity;
  }

  async update(id: string, data: Partial<Omit<T, 'id'>>): Promise<T | null> {
    const result = await this.collection.findOneAndUpdate(
      { id } as any,
      { $set: data } as any,
      { returnDocument: 'after' }
    );
    return result ?? null;
  }

  async delete(id: string): Promise<boolean> {
    const result = await this.collection.deleteOne({ id } as any);
    return result.deletedCount > 0;
  }
}

export class OrderRepository extends BaseRepository<Order> {
  async validate(data: Omit<Order, 'id'>): Promise<void> {
    if (!data.customerId) throw new ValidationError('Customer ID is required');
    if (!data.items?.length) throw new ValidationError('Order must have at least one item');
    if (data.items.some(i => i.quantity <= 0)) throw new ValidationError('Item quantity must be positive');
  }

  async findByCustomer(customerId: string, status?: OrderStatus): Promise<Order[]> {
    const filter: Partial<Order> = { customerId };
    if (status) filter.status = status;
    return this.findMany(filter, { sort: { createdAt: -1 } });
  }

  async calculateTotal(orderId: string): Promise<number> {
    const order = await this.findById(orderId);
    if (!order) throw new NotFoundError(`Order ${orderId} not found`);
    return order.items.reduce((sum, item) => sum + item.price * item.quantity, 0);
  }
}
