export async function fetchUser(
  identifier: string | { email: string },
  options: {
    includeProfile?: boolean;
    includePermissions?: boolean;
    cache?: boolean;
  } = {}
): Promise<UserResponse | null> {
  const cacheKey = typeof identifier === 'string' ? identifier : identifier.email;

  if (options.cache !== false) {
    const cached = await redis.get(`user:${cacheKey}`);
    if (cached) return JSON.parse(cached);
  }

  const user = typeof identifier === 'string'
    ? await db.users.findOne({ id: identifier })
    : await db.users.findOne({ email: identifier.email });

  if (!user) return null;

  const response: UserResponse = { ...user };
  if (options.includeProfile) response.profile = await db.profiles.findOne({ userId: user.id });
  if (options.includePermissions) response.permissions = await getPermissions(user.id);

  if (options.cache !== false) {
    await redis.setex(`user:${cacheKey}`, 300, JSON.stringify(response));
  }

  return response;
}
